//! TypeScript emission for the Svelte → `.svelte.ts` pipeline.
//!
//! ### Status: scaffolding pass + per-file render name + import hoisting
//!
//! Emits a TypeScript wrapper around each Svelte component:
//!
//! ```text
//! // generated by svelte-check-native; do not edit
//! [module script verbatim]
//! [hoisted imports from instance script]
//! function $$render_<8-char-content-hash>() {
//!     [instance script body, with imports blanked out]
//!     async function __svn_tpl_check() {
//!         [for-loops for each {#each} block]
//!         [action-attrs / bind-pair declarations]
//!     }
//!     void (__svn_tpl_check, ...synthesized names);
//! }
//! $$render_<hash>;
//! ```
//!
//! Per-file `$$render` naming prevents the TS2393 "duplicate function
//! implementation" cascade that fires when multiple components in one
//! tsgo project declare the same global. Hash is derived from the
//! source path so it's stable across runs.
//!
//! Import hoisting prevents TS1232: ES `import` declarations are illegal
//! inside a function body, so we lift every `import` statement out of
//! the wrapped instance script to module top-level.
//!
//! ### What's still NOT here (next emit-fidelity rounds)
//!
//! - Real svelte type shims (`helpers.d.ts` shipped to the cache).
//!   Currently we don't emit any svelte-aware types; users get the real
//!   svelte package's types only if they have it installed in
//!   node_modules.
//! - Component-instantiation type-checking (props, slots, events) —
//!   needed for TS2741 "missing required prop" diagnostics.
//! - Element attribute type-checking — needed for HTML attribute
//!   correctness.
//! - Lifting template `{expr}` interpolations into the template-check
//!   function with proper scope.
//! - Real source maps so line/column point at the `.svelte` source.
//!   Today we use a fixed line offset which only works for diagnostics
//!   inside the verbatim script body.

#![cfg_attr(test, allow(clippy::expect_used, clippy::unwrap_used))]

mod script_split;
mod state_nullish_rewrite;
mod sveltekit;

use std::fmt::Write;
use std::path::Path;

use std::collections::HashSet;

use oxc_allocator::Allocator;
use smol_str::SmolStr;
use svn_analyze::{
    TemplateSummary, collect_top_level_bindings, find_props, find_store_refs_with_bindings,
    find_template_refs,
};
use svn_parser::Document;
use svn_parser::{EachBlock, Fragment, Node, SnippetBlock, parse_script_body};

use crate::script_split::split_imports;

/// Output of [`emit_document`].
#[derive(Debug, Clone)]
pub struct EmitOutput {
    pub typescript: String,
    /// The synthesized name we used for this file's render function — so
    /// callers (e.g. test code) can assert on it without re-deriving the
    /// hash.
    pub render_name: SmolStr,
    /// Line map: for each contiguous run of verbatim source content that
    /// landed in the overlay, an entry mapping the overlay line range
    /// back to the source line range.
    pub line_map: Vec<LineMapEntry>,
}

/// Single line mapping from the overlay back to the original `.svelte`
/// source. Both line numbers are 1-based.
///
/// Within `[overlay_start_line, overlay_end_line)`, line N maps to
/// source line `source_start_line + (N - overlay_start_line)`.
///
/// Lines that fall outside any entry's range are synthesized (header
/// comment, function wrapper, void block) and have no source mapping —
/// the diagnostic mapper clamps them to `source_start_line` of the
/// nearest preceding entry, or to line 1 if none exists.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct LineMapEntry {
    pub overlay_start_line: u32,
    pub overlay_end_line: u32,
    pub source_start_line: u32,
}

/// Emit the TypeScript scaffold for a parsed Svelte document.
///
/// `source_path` is used to derive a per-file unique render-function name
/// (hash of the canonical path). Callers without a real path (unit tests)
/// pass any stable string; the resulting hash will be identical for the
/// same input string, which is fine.
pub fn emit_document(
    doc: &Document<'_>,
    fragment: &Fragment,
    summary: &TemplateSummary,
    source_path: &Path,
) -> EmitOutput {
    let render_name = render_function_name(source_path);
    emit_document_with_render_name(doc, fragment, summary, render_name, source_path)
}

fn emit_document_with_render_name(
    doc: &Document<'_>,
    fragment: &Fragment,
    summary: &TemplateSummary,
    render_name: SmolStr,
    source_path: &Path,
) -> EmitOutput {
    let estimated_capacity = doc.source.len().saturating_mul(2).saturating_add(256);
    let mut out = String::with_capacity(estimated_capacity);
    let mut line_map: Vec<LineMapEntry> = Vec::new();

    out.push_str("// generated by svelte-check-native; do not edit\n");

    // Module script content (already at module level — no special handling).
    if let Some(module_script) = &doc.module_script {
        let overlay_line = current_line(&out);
        let source_line = source_line_at(doc.source, module_script.content_range.start);
        let line_count = count_lines(module_script.content);
        out.push_str(module_script.content);
        if !module_script.content.ends_with('\n') {
            out.push('\n');
        }
        if line_count > 0 {
            line_map.push(LineMapEntry {
                overlay_start_line: overlay_line,
                overlay_end_line: overlay_line + line_count,
                source_start_line: source_line,
            });
        }
    }

    // `<script generics="T extends ...">` — pulled from the parser's
    // ScriptSection::generics. Extracted up front so script_split can
    // decide whether to hoist bare `type`/`interface` declarations out
    // of the render body (they'd lose access to the `T` generic if
    // lifted to module scope).
    let generics = extract_generics_attr(doc);

    // Extract the Props type's root name (if any) up front so
    // script_split can decide whether a given `type`/`interface`
    // declaration IS the Props annotation — Props always hoists, even
    // when its body references locals via `typeof`, because consumers
    // need the Props type visible at module scope to get typed
    // contextual flow. Non-Props types that reference body-locals via
    // `typeof` stay body-scoped so `keyof typeof X` resolves against
    // the real declaration rather than the lossy declare-const stub.
    let prop_type_root_for_split: Option<String> = doc.instance_script.as_ref().and_then(|s| {
        let alloc = Allocator::default();
        let parsed = parse_script_body(&alloc, s.content, s.lang);
        svn_analyze::find_props_type_source(&parsed.program, s.content)
            .as_deref()
            .and_then(|t| root_type_name(t.trim()))
    });

    // Rewrite `let X: Type = $state(null | undefined)` to
    // `$state<Type>(null | undefined)` so the single-T `$state` shim
    // overload picks `T` from the explicit generic (sourced from the
    // annotation) rather than collapsing to `null` from the argument.
    // See `state_nullish_rewrite` for the full reasoning — this pass
    // is the reason we can keep `$state` as a single-T overload: the
    // literal-type overloads we'd otherwise need for the bind:this
    // pattern collide with TypeScript's overload resolution on
    // `$state<Promise<T>>(new Promise(() => {}))`, where the explicit
    // `<T>` no longer propagates as contextual type to the argument.
    let rewritten_content: Option<String> = doc
        .instance_script
        .as_ref()
        .map(|s| state_nullish_rewrite::rewrite(s.content, s.lang));

    // Hoist imports out of the instance script. Required because the
    // instance body gets wrapped in `function $$render() { ... }` and ES
    // `import` declarations can't appear inside a function (TS1232).
    let split = doc.instance_script.as_ref().map(|s| {
        let content = rewritten_content.as_deref().unwrap_or(s.content);
        split_imports(
            content,
            s.lang,
            generics.is_some(),
            prop_type_root_for_split.as_deref(),
        )
    });

    if let Some(s) = &split {
        if !s.hoisted.is_empty() {
            // Build a per-import line-map entry so a diagnostic on a
            // hoisted import line points at the original `<script>`
            // import line. Each hoisted statement is concatenated
            // verbatim into `s.hoisted` — line counts inside each
            // statement match the source 1:1, so we emit one entry per
            // statement.
            if let Some(instance) = &doc.instance_script {
                let mut overlay_cursor = current_line(&out);
                let bytes = s.hoisted.as_bytes();
                let mut byte = 0usize;
                for &source_offset in &s.hoisted_byte_offsets {
                    // Each hoisted statement runs until either the next
                    // `\n` followed by a non-blank line, or the next
                    // hoisted offset's projection in the concatenated
                    // string. Simplest: count lines until we hit the
                    // next statement (we know there's an extra `\n`
                    // between statements).
                    let stmt_start_byte = byte;
                    while byte < bytes.len() && bytes[byte] != b'\n' {
                        byte += 1;
                    }
                    // Multi-line imports: keep walking while indented
                    // continuations or close-brace tokens follow.
                    while byte < bytes.len() {
                        let next = byte + 1;
                        if next >= bytes.len() {
                            break;
                        }
                        // If the next char starts a new statement that
                        // also appears in `hoisted_byte_offsets`, stop
                        // here. Otherwise keep walking to allow
                        // multi-line imports.
                        let after_nl = bytes[next];
                        if after_nl == b'\n' {
                            // Blank line — definitely end of statement.
                            byte += 1;
                            break;
                        }
                        // Heuristic: if the line starts with an alpha
                        // character at column 0, it's a new statement.
                        if after_nl.is_ascii_alphabetic() {
                            byte += 1;
                            break;
                        }
                        byte += 1;
                        while byte < bytes.len() && bytes[byte] != b'\n' {
                            byte += 1;
                        }
                    }
                    let stmt_text = &s.hoisted[stmt_start_byte..byte];
                    let stmt_line_count = count_lines(stmt_text).max(1);
                    let source_line =
                        source_line_at(doc.source, instance.content_range.start + source_offset);
                    line_map.push(LineMapEntry {
                        overlay_start_line: overlay_cursor,
                        overlay_end_line: overlay_cursor + stmt_line_count,
                        source_start_line: source_line,
                    });
                    overlay_cursor += stmt_line_count;
                    // Skip the trailing newline we wrote.
                    if byte < bytes.len() && bytes[byte] == b'\n' {
                        byte += 1;
                    }
                }
            }
            out.push_str(&s.hoisted);
            if !s.hoisted.ends_with('\n') {
                out.push('\n');
            }
        }
    }

    // `<script generics="T extends ...">` (extracted above) — expose
    // the type params as generics on the wrapping function so
    // references inside the body resolve. Falls back to no-generics
    // when the attribute is absent.
    //
    // The wrapper is `async` because Svelte 5 components are allowed to
    // use top-level `await` in their `<script>` body (TLA via Vite/SvelteKit
    // is supported); without `async` we'd report TS1308 for those.
    match &generics {
        Some(g) => {
            let _ = writeln!(out, "async function {render_name}<{g}>() {{");
        }
        None => {
            let _ = writeln!(out, "async function {render_name}() {{");
        }
    }
    // Analyze the instance script for store refs, destructured props, and
    // the set of script-declared bindings. The bindings are intersected
    // with template-referenced identifiers below to drive per-template
    // void-refs (closes the TS6133 gap for imports/locals used only in
    // markup).
    //
    // Bindings come from both the module script (`<script module>`) and
    // the instance script — names from either scope are visible in the
    // template, so both must seed the void-ref intersection.
    //
    // Two oxc parses are needed for the instance script: `s.body` has
    // imports blanked out (so store-ref scanning and prop detection see
    // only the body), but binding collection must see the *original*
    // content so imports count as declared names.
    let mut script_bindings: HashSet<String> = HashSet::new();
    if let Some(module_script) = &doc.module_script {
        let alloc_mod = Allocator::default();
        let parsed_mod = parse_script_body(&alloc_mod, module_script.content, module_script.lang);
        collect_top_level_bindings(&parsed_mod.program, &mut script_bindings);
    }

    let (prop_names, prop_type_source): (Vec<SmolStr>, Option<String>) =
        if let (Some(_s), Some(instance)) = (&split, &doc.instance_script) {
            // Scan bindings + props against the *original* script content
            // (imports included). Using the imports-blanked body would
            // miss store names imported from external modules (e.g.
            // SvelteKit's `import { page } from '$app/stores'` plus
            // template uses of `$page.data.foo`).
            let alloc_orig = Allocator::default();
            let parsed_orig = parse_script_body(&alloc_orig, instance.content, instance.lang);
            let props: Vec<SmolStr> = find_props(&parsed_orig.program)
                .into_iter()
                .map(|p| p.local_name)
                .collect();

            // Capture the `$props()` type annotation (if any) so the
            // default export below can be typed as
            // `Component<PropType>`. Without this, `typeof X` for our
            // overlay default resolves to the weak declared type and
            // every `<X cb={(arg) => ...}>` destructure binding reads
            // as implicit-any via `ComponentProps<any> = any`.
            let mut ty =
                svn_analyze::find_props_type_source(&parsed_orig.program, instance.content);

            // SvelteKit auto-typing: when the file is a route component
            // (`+page.svelte`, `+layout.svelte`, …) and the user wrote
            // an untyped `$props()` destructure, synthesize a Props
            // shape from the known kit-auto-typed prop names so `data`
            // gets `PageData` / `LayoutData`, `form` gets `ActionData`,
            // etc. Users writing `let { data } = $props()` expect this
            // without writing the annotation themselves — upstream
            // svelte2tsx injects the same shape. No-op when the user
            // already wrote their own `$props()` annotation or when the
            // file is non-route.
            if ty.is_none() {
                if let Some(kind) = sveltekit::route_kind(source_path) {
                    let names_borrow: Vec<&str> = props.iter().map(|s| s.as_str()).collect();
                    ty = sveltekit::synthesize_route_props_type(kind, &names_borrow);
                }
            }

            collect_top_level_bindings(&parsed_orig.program, &mut script_bindings);
            (props, ty)
        } else {
            (Vec::new(), None)
        };

    // Store auto-subscribe scan happens AFTER both module + instance
    // bindings are collected, so a `$properties` use in instance can
    // resolve to a `properties` declared in `<script module>`.
    let mut store_refs: Vec<SmolStr> = {
        let mut accumulated: Vec<SmolStr> = Vec::new();
        let mut seen: HashSet<String> = HashSet::new();
        let push_unique =
            |found: Vec<SmolStr>, seen: &mut HashSet<String>, out: &mut Vec<SmolStr>| {
                for name in found {
                    if seen.insert(name.to_string()) {
                        out.push(name);
                    }
                }
            };
        if let Some(module_script) = &doc.module_script {
            push_unique(
                find_store_refs_with_bindings(module_script.content, &script_bindings),
                &mut seen,
                &mut accumulated,
            );
        }
        if let Some(instance) = &doc.instance_script {
            push_unique(
                find_store_refs_with_bindings(instance.content, &script_bindings),
                &mut seen,
                &mut accumulated,
            );
        }
        accumulated
    };

    // Walk template expressions for identifier references. A single walk
    // produces both:
    //   - `template_void_refs`: refs that match a script binding —
    //     consumed by emit_void_block so TS6133 doesn't fire on
    //     imports/locals only used in markup
    //   - additional `$store` refs to seed the auto-subscribe alias
    //     declarations: a store imported in the script but only
    //     auto-subscribed in the template (`{$page.data.x}`) needs the
    //     same `let $page: any;` declaration as a script-side use.
    let (template_void_refs, template_store_refs) = if script_bindings.is_empty() {
        (Vec::new(), Vec::new())
    } else {
        let already: HashSet<&str> = store_refs
            .iter()
            .chain(prop_names.iter())
            .map(|s| s.as_str())
            .collect();
        let mut tpl_voids = Vec::new();
        let mut tpl_stores = Vec::new();
        let mut store_seen: HashSet<String> = store_refs.iter().map(|s| s.to_string()).collect();
        for name in find_template_refs(fragment, doc.source) {
            // `$foo` where `foo` is a script binding (and not already a
            // declared store) — synthesize the auto-subscribe alias.
            if let Some(base) = name.as_str().strip_prefix('$') {
                if script_bindings.contains(base) && store_seen.insert(name.to_string()) {
                    tpl_stores.push(name.clone());
                    continue;
                }
            }
            if script_bindings.contains(name.as_str()) && !already.contains(name.as_str()) {
                tpl_voids.push(name);
            }
        }
        (tpl_voids, tpl_stores)
    };
    store_refs.extend(template_store_refs);

    // Store auto-subscribe aliases: declare a typed `let $store!:
    // __SvnStoreValue<typeof store>;` for every detected `$ident`.
    //
    // Why `let !` and not `const = expr`:
    //   - `$store` references in the body need the alias to be visible
    //     at the top of the function, but the underlying `store` may be
    //     declared FURTHER DOWN in the body (or hoisted above as an
    //     import). A value-position reference like `__svn_store_get(store)`
    //     fires TS2448 ("used before declaration") for body-declared
    //     stores. A type-position reference (`typeof store`) is resolved
    //     lazily by TS and works regardless of declaration order.
    //   - `__SvnStoreValue<typeof store>` extracts the value type out of
    //     the store wrapper using a conditional infer. Without this,
    //     downstream code (`$store.bar`, `$store.map(...)`) would see
    //     `any` and cascade into TS7006/TS18046/TS2339/TS2698 hits.
    //   - The `!` definite-assignment assertion suppresses TS2454; we
    //     never actually assign to `$store` ourselves, but Svelte's
    //     compiler treats the identifier as initialized at runtime.
    for name in &store_refs {
        let base = name.strip_prefix('$').unwrap_or(name);
        let _ = writeln!(out, "    let {name}!: __SvnStoreValue<typeof {base}>;");
    }

    if let Some(s) = &split {
        if let Some(instance) = &doc.instance_script {
            let overlay_line = current_line(&out);
            let source_line = source_line_at(doc.source, instance.content_range.start);
            let line_count = count_lines(&s.body);
            out.push_str(&s.body);
            if !s.body.ends_with('\n') {
                out.push('\n');
            }
            if line_count > 0 {
                line_map.push(LineMapEntry {
                    overlay_start_line: overlay_line,
                    overlay_end_line: overlay_line + line_count,
                    source_start_line: source_line,
                });
            }
        }
    }

    // Collect every `let <name>: T;` that needs a `!` definite-assignment
    // assertion to satisfy strict flow analysis. Two sources:
    //
    //   1. `bind:this` targets — the user's `bind:this={x}` pattern
    //      assigns `x` asynchronously after mount; TS can't see that.
    //   2. `export`-stripped locals — `export let foo: T` in the
    //      script becomes `let foo: T` in the body after
    //      script_split removes the `export` keyword. The symbol is
    //      consumed by the template (`{#if foo}`, `<X prop={foo}>`)
    //      but never initialized in the body. Post-Phase-1 we emit
    //      template `{#if foo}` as a real TS `if ((foo))`, which
    //      reads the uninitialized `let foo: T;` and fires TS2454.
    //
    // The `rewrite_definite_assignment_in_place` pass only touches
    // declarations that have a `:` type annotation and NO `=`
    // initializer, so adding names here is safe for `export let foo
    // = defaultValue` and `export let foo` (no annotation) — both
    // skip the rewrite.
    let mut def_assign_names: Vec<SmolStr> = summary
        .bind_this_targets
        .iter()
        .map(|t| t.name.clone())
        .collect();
    if let Some(s) = &split {
        for name in &s.exported_locals {
            if !def_assign_names.iter().any(|n| n == name) {
                def_assign_names.push(name.clone());
            }
        }
    }
    // Also definite-assign every store whose auto-subscribe alias
    // `$store` got synthesized above. Svelte promises `$store` reads a
    // value from the store runtime, but the UNDERLYING `store` local
    // may be declared as `let store: Writable<T>` (no initializer) and
    // only assigned inside a reactive branch. Without the `!`, TS2454
    // fires at the type-declaration line because flow analysis sees
    // `typeof store` being read before all branches assign. Safe to
    // enable broadly: the definite-assign rewrite only touches `let
    // NAME: Type` declarations with no initializer and no `!`, so
    // store imports, store `const` declarations, and `let store =
    // writable(0)` patterns are all unaffected.
    for name in &store_refs {
        let base = SmolStr::from(name.strip_prefix('$').unwrap_or(name));
        if !def_assign_names.iter().any(|n| n == &base) {
            def_assign_names.push(base);
        }
    }
    rewrite_definite_assignment_in_place(&mut out, &def_assign_names);

    out.push_str("    async function __svn_tpl_check() {\n");
    out.push_str("        // template type-check body (incremental)\n");
    // `{@const}` declarations are emitted INLINE in the template-walk
    // pass (see `emit_at_const_if_any`) — as a `const <pattern> =
    // <expr>;` at the exact point in the template where the tag
    // appears. Inline emission pins the inferred type so subsequent
    // `{#if NAME === '...'}` narrows via TS control-flow analysis,
    // and destructuring patterns (`{@const [a, { b }] = tuple}`) work
    // for free. A top-level `let NAME: any = undefined;` stub
    // (previous behavior) would shadow the inline const — every
    // block-scope `const` re-use would fire TS6133 on the unused
    // outer `let`. References out of the declaring block's scope are
    // now (correctly) "name not found" errors.
    emit_action_attrs_declarations(&mut out, summary);
    emit_bind_pair_declarations(&mut out, summary);
    // Index component instantiations by source byte offset so the
    // template walker can emit each prop-check inline at the component
    // node's position — i.e. inside the enclosing `{#each}` / `{#if}` /
    // `{#snippet}` scope. Emitting the checks as a flat block after the
    // walk put every check at the top level of `__svn_tpl_check`, which
    // silently broke any check whose prop expressions referenced a
    // binding introduced by a block (each-as item, each-index, snippet
    // param, etc.).
    let instantiations_by_start: std::collections::HashMap<
        u32,
        &svn_analyze::ComponentInstantiation,
    > = summary
        .component_instantiations
        .iter()
        .map(|i| (i.node_start, i))
        .collect();
    emit_template_body(&mut out, doc.source, fragment, 2, &instantiations_by_start);
    out.push_str("    }\n");

    let exported_locals: Vec<SmolStr> = split
        .as_ref()
        .map(|s| s.exported_locals.clone())
        .unwrap_or_default();

    // Build the `{ name: sig; ... }` object type for collected exports.
    // Used two places below:
    //   - as the Exports type parameter of `Component<Props, Exports>`
    //     on the VALUE declaration, so `ReturnType<typeof Foo>` carries
    //     user exports (common pattern: `let ref: ReturnType<typeof X>
    //     = $state()` for bind:this targets).
    //   - as an `& { name: sig }` intersection on the TYPE alias, so
    //     `let ref: Foo` picks up the same shape.
    let exports_object: Option<String> = split.as_ref().and_then(|s| {
        if s.export_type_infos.is_empty() {
            return None;
        }
        let mut buf = String::from("{ ");
        for info in &s.export_type_infos {
            buf.push_str(info.name.as_str());
            buf.push_str(": ");
            match &info.type_source {
                Some(t) => buf.push_str(t),
                None => buf.push_str("any"),
            }
            buf.push_str("; ");
        }
        buf.push('}');
        Some(buf)
    });
    let exports_clause = exports_object
        .as_deref()
        .map(|e| format!(" & {e}"))
        .unwrap_or_default();
    let component_exports_arg = exports_object
        .as_deref()
        .map(|e| format!(", {e}"))
        .unwrap_or_default();
    emit_void_block(
        &mut out,
        summary,
        &store_refs,
        &prop_names,
        &template_void_refs,
        &exported_locals,
    );

    out.push_str("}\n");
    let _ = writeln!(out, "{render_name};");

    // Default export so `import Foo from './Foo.svelte'` resolves to
    // a valid module member. Emits as a `declare function`: the props
    // parameter of the call signature is what carries the Props type
    // into consumers. A consumer's `<Foo prop={...}>` template becomes
    // `Foo(__svn_any(), {prop: ...})`, and TS contextually types the
    // prop object from the function's second parameter — which is the
    // only shape that makes callback-prop destructures
    // (`onclick={({x}) => ...}`) and snippet children contextually
    // pick up their parameter types.
    //
    // Three cases:
    //   1. Typed Props + generics: emit
    //        declare function __svn_component_default<T>(__anchor, props: Props): any
    //      where Props may reference T. The generic's scope is the
    //      function signature, so T resolves module-scope.
    //   2. Typed Props only: same shape without the generic list.
    //   3. Untyped (no $props() annotation): emit the permissive
    //        declare function __svn_component_default(__anchor, props: any): any
    //      — consumers can pass any shape. Preserves the pre-refactor
    //      "silently accept" behaviour for Svelte-4-style or
    //      <script>-less components.
    //
    // A same-named type alias is also emitted so user code that uses
    // the default import as a type (`let x: Foo`, `$state<Foo>(...)`)
    // doesn't fire TS2749. The alias resolves to a structurally
    // matching function-type.
    // Three cases: typed+generic, typed non-generic, untyped.
    //
    // The Props source has to be "safe" to reference at module scope:
    // either a literal shape (`{ item: T }`) or a named type whose
    // declaration was hoisted by script_split. Bare named types that
    // stay body-scoped (either because they reference the script's
    // generic without re-binding it, or because they reference a
    // body-level const via `typeof`) can't be named from the
    // default-export declaration — emit falls back to `any` for
    // those.
    let prop_ty_is_literal = prop_type_source
        .as_deref()
        .is_some_and(|t| t.trim().starts_with('{'));
    let prop_ty_root_name = prop_type_source
        .as_deref()
        .and_then(|t| root_type_name(t.trim()));
    // Consider a named Props type module-scope-visible if either (a)
    // script_split hoisted it out of the instance script, or (b) it's
    // declared in the `<script module>` section (which emits verbatim
    // at module scope), or (c) it's imported as a type at the module
    // top level. The last case is the common
    // `import type { FooProps } from './types'` pattern.
    let module_script_text = doc.module_script.as_ref().map(|s| s.content).unwrap_or("");
    let prop_ty_module_visible = prop_ty_root_name.as_deref().is_some_and(|n| {
        split
            .as_ref()
            .is_some_and(|s| s.hoisted_type_names.contains(n))
            || module_script_declares_type(module_script_text, n)
            || split.as_ref().is_some_and(|s| imports_name(&s.hoisted, n))
    });
    let ty_safe_in_generic_scope = prop_ty_is_literal || prop_ty_module_visible;
    let ty_safe_in_module_scope = prop_ty_is_literal || prop_ty_module_visible;
    // Default export typed as Svelte 5's `Component<Props>` (function
    // form). This shape is chosen to satisfy the constraint on
    // svelte's built-in `ComponentProps<T>` helper — which accepts
    // `T extends Component<any, any, string> | SvelteComponent<...>`
    // — so user code that writes `ComponentProps<typeof Foo>`
    // resolves Props correctly. A class-based default with narrower
    // Props fails `SvelteComponent<any>`'s invariant-in-Props
    // constraint; the function form sidesteps that entirely.
    //
    // Consumer-side emission wraps the value through
    // `__svn_ensure_component`, which synthesizes a construct
    // signature for callable components and passes class components
    // through unchanged:
    //
    //     { const $$_C0 = __svn_ensure_component(Comp);
    //       new $$_C0({ target: __svn_any(), props: { ... } }); }
    //
    // The wrapper's intermediate local is what makes generic
    // components' `<T>` resolve at the `new` site (TS binds generics
    // against the concrete prop values there, not at the
    // `__svn_ensure_component` call). Validated end-to-end in
    // design/phase_a/ — including classes imported from third-party
    // libraries (lucide-svelte, phosphor-svelte, bits-ui).
    // A same-named type alias is emitted alongside the value so user
    // code that uses the default import as a type
    // (`let ref: MyComp`, `$state<MyComp>(...)`, `(el as MyComp)`)
    // resolves without firing TS2749 "refers to a value, but is
    // being used as a type here". The alias resolves to the
    // InstanceType of the Component's construct wrapper — roughly
    // `{ $on?, $set? } & Exports` for real-svelte `Component<Props>`
    // — which is what upstream's svelte2tsx surfaces under the same
    // name. Consumer code that writes `let x: MyComp` picks up the
    // instance shape, same as before the callable-shape refactor.
    match (&prop_type_source, &generics) {
        (Some(ty), Some(g)) if ty_safe_in_generic_scope => {
            let _ = writeln!(
                out,
                "declare const __svn_component_default: <{g}>(__anchor: any, props: Partial<{ty}>) => {};",
                exports_object.as_deref().unwrap_or("any"),
            );
            let _ = writeln!(
                out,
                "declare type __svn_component_default<{g}> = import('svelte').SvelteComponent<{ty}>{exports_clause};"
            );
        }
        (Some(ty), None) if ty_safe_in_module_scope => {
            let _ = writeln!(
                out,
                "declare const __svn_component_default: import('svelte').Component<{ty}{component_exports_arg}>;"
            );
            let _ = writeln!(
                out,
                "declare type __svn_component_default = import('svelte').SvelteComponent<{ty}>{exports_clause};"
            );
        }
        _ => {
            let _ = writeln!(
                out,
                "declare const __svn_component_default: import('svelte').Component<Record<string, any>{component_exports_arg}>;"
            );
            let _ = writeln!(
                out,
                "declare type __svn_component_default = import('svelte').SvelteComponent<Record<string, any>>{exports_clause};"
            );
        }
    }
    out.push_str("export default __svn_component_default;\n");

    // `.svelte` import specifiers are left unchanged. TS resolves
    // them via `allowArbitraryExtensions` + the ambient
    // `Foo.d.svelte.ts` sidecar written by the typecheck cache writer,
    // which re-exports from the real overlay at `Foo.svelte.svn.ts`.
    //
    // Not rewriting also preserves the bundler-mode auto-append path
    // for `import X from './Foo.svelte'` where `Foo.svelte.ts` is the
    // user's runes module (Svelte 5 convention, e.g. bits-ui,
    // shadcn-svelte) — TS tries `.svelte` literal, then `.svelte.ts`,
    // then our ambient, in that order. Rewriting to
    // `./Foo.svelte.svn.ts` would short-circuit the runes-module
    // fallback.

    EmitOutput {
        typescript: out,
        render_name,
        line_map,
    }
}

/// Byte-scan a script section for `type NAME`, `interface NAME`,
/// `export type NAME`, or `export interface NAME` declarations.
/// Returns true if `name` appears as a declared type. Used by emit to
/// check whether a Props type referenced from a consumer-scope
/// declaration will resolve at module scope.
///
/// Not a full parser — matches the common case of a top-of-line type
/// keyword followed by whitespace and the identifier. String-literal
/// and comment false-positives (writing `// interface Foo` in a
/// comment) resolve toward "visible"; emit then declares `Component<Foo>`
/// which fires TS2304 only if the user genuinely forgot to declare
/// Foo, a clear error they can fix.
fn module_script_declares_type(text: &str, name: &str) -> bool {
    if name.is_empty() {
        return false;
    }
    for prefix in ["type ", "interface "] {
        let needle = format!("{prefix}{name}");
        for (idx, _) in text.match_indices(&needle) {
            let before_ok = idx == 0 || {
                let b = text.as_bytes()[idx - 1];
                !b.is_ascii_alphanumeric() && b != b'_' && b != b'$'
            };
            let after_idx = idx + needle.len();
            let after_ok = after_idx == text.len() || {
                let b = text.as_bytes()[after_idx];
                !b.is_ascii_alphanumeric() && b != b'_' && b != b'$'
            };
            if before_ok && after_ok {
                return true;
            }
        }
    }
    false
}

/// Byte-scan hoisted import declarations for `name` appearing in an
/// `import type { ... }` or `import { ... }` clause. Used to check
/// whether a Props type referenced by the consumer emit comes from a
/// type-only module import.
fn imports_name(hoisted: &str, name: &str) -> bool {
    if name.is_empty() {
        return false;
    }
    // Fast path: check any `import` statement that mentions the name
    // as a braced specifier. Matches `{ name }`, `{ name, ... }`,
    // `{ ..., name }`, `{ name as Alias }`, `{ type name }`, etc.
    for (idx, _) in hoisted.match_indices(name) {
        let before = idx.checked_sub(1).map(|i| hoisted.as_bytes()[i]);
        let after = hoisted.as_bytes().get(idx + name.len()).copied();
        let bounded = before.is_none_or(|b| !b.is_ascii_alphanumeric() && b != b'_' && b != b'$')
            && after.is_none_or(|b| !b.is_ascii_alphanumeric() && b != b'_' && b != b'$');
        if !bounded {
            continue;
        }
        // Scan backward to the nearest `import`, stopping at a prior
        // `;` or `\n\n` (statement boundary). If we hit `import` with
        // an open `{` between it and the name, it's an import
        // specifier.
        let before_text = &hoisted[..idx];
        if let Some(import_pos) = before_text.rfind("import") {
            let between = &before_text[import_pos + "import".len()..];
            if between.contains('{') && !between.contains('}') {
                return true;
            }
        }
    }
    false
}

/// Extract the leading identifier of a TypeScript type source, if the
/// source starts with a reference to a named type (e.g. `Props`,
/// `Props<T>`, `ChannelMessageProps`). Returns `None` for literal
/// shapes (`{ ... }`), tuple/array (`[...]`), and other non-reference
/// starts. Used by emit to decide whether a named-type Props can be
/// safely mentioned at module scope.
fn root_type_name(ty: &str) -> Option<String> {
    let bytes = ty.as_bytes();
    if bytes.is_empty() {
        return None;
    }
    let first = bytes[0];
    if !(first.is_ascii_alphabetic() || first == b'_' || first == b'$') {
        return None;
    }
    let mut end = 0usize;
    while end < bytes.len()
        && (bytes[end].is_ascii_alphanumeric() || bytes[end] == b'_' || bytes[end] == b'$')
    {
        end += 1;
    }
    Some(ty[..end].to_string())
}

/// 1-based line number of the next character that would be appended to `s`.
#[inline]
fn current_line(s: &str) -> u32 {
    1 + s.bytes().filter(|&b| b == b'\n').count() as u32
}

/// 1-based line number at the given byte offset in `source`.
#[inline]
fn source_line_at(source: &str, offset: u32) -> u32 {
    1 + source[..offset as usize]
        .bytes()
        .filter(|&b| b == b'\n')
        .count() as u32
}

/// Count the number of complete lines in `text` (the count of `\n` plus
/// 1 if the text doesn't end with a newline and is non-empty). Used to
/// derive an end-line for line-map entries.
#[inline]
fn count_lines(text: &str) -> u32 {
    let nl = text.bytes().filter(|&b| b == b'\n').count() as u32;
    if text.is_empty() {
        0
    } else if text.ends_with('\n') {
        nl
    } else {
        nl + 1
    }
}

/// Derive a per-file render function name. Hash of the source path's
/// canonical form prevents collisions when multiple components in the
/// same overlay project would otherwise both produce `function $$render()`
/// (TS2393 "Duplicate function implementation").
///
/// The hash is the first 8 hex chars of blake3 — collision-free for any
/// realistic project size.
fn render_function_name(source_path: &Path) -> SmolStr {
    let bytes = source_path.as_os_str().to_string_lossy();
    let hash = blake3::hash(bytes.as_bytes());
    let hex = hash.to_hex();
    let short = &hex.as_str()[..8];
    SmolStr::from(format!("$$render_{short}"))
}

/// Extract the `generics=` attribute value from the instance `<script>`
/// if present.
///
/// Svelte 5's syntax for declaring generic type params on a component:
///
/// ```svelte
/// <script lang="ts" generics="T extends Item, K extends keyof T">
/// ```
///
/// The value is spliced verbatim into our wrapping function as
/// `function $$render<T extends Item, K extends keyof T>() { ... }` so
/// any references to `T` / `K` inside the script body resolve correctly.
///
/// Parsing lives in the structural parser (`ScriptSection::generics`);
/// this helper just re-types the already-extracted `Option<String>` as
/// a `SmolStr` and guards against callers that pass in a document
/// without an instance script.
fn extract_generics_attr(doc: &Document<'_>) -> Option<SmolStr> {
    let script = doc.instance_script.as_ref()?;
    script.generics.as_deref().map(SmolStr::from)
}

/// Walk the fragment tree and emit per-construct scaffolding.
///
/// Currently emits a `for`-of loop for each `{#each}` block and recurses
/// into other block bodies / element children. Component-prop excess
/// checks are emitted inline at each `<Component>` position so they
/// sit inside the correct enclosing block scope.
fn emit_template_body(
    out: &mut String,
    source: &str,
    fragment: &Fragment,
    depth: usize,
    insts: &std::collections::HashMap<u32, &svn_analyze::ComponentInstantiation>,
) {
    // Hoist `{#snippet name(...)}` names declared at this fragment so
    // sibling component-prop checks (`<X slot={name}>`) resolve them.
    // When any hoist happens, the whole walk is wrapped in a fresh `{}`
    // lexical scope so the declarations don't leak to other fragments
    // at the same depth — e.g. two `<Wrapper>{#snippet action()}...`
    // siblings would otherwise redeclare `action` in the same scope
    // and fire TS2451.
    let snippets: Vec<&SnippetBlock> = fragment
        .nodes
        .iter()
        .filter_map(|n| match n {
            Node::SnippetBlock(b) => Some(b),
            _ => None,
        })
        .collect();
    if snippets.is_empty() {
        for node in &fragment.nodes {
            emit_template_node(out, source, node, depth, insts);
        }
        return;
    }
    let indent = "    ".repeat(depth);
    let inner = "    ".repeat(depth + 1);
    let _ = writeln!(out, "{indent}{{");
    for s in &snippets {
        let _ = writeln!(out, "{inner}const {}: any = undefined;", s.name);
        let _ = writeln!(out, "{inner}void {};", s.name);
    }
    for node in &fragment.nodes {
        emit_template_node(out, source, node, depth + 1, insts);
    }
    let _ = writeln!(out, "{indent}}}");
}

fn emit_template_node(
    out: &mut String,
    source: &str,
    node: &Node,
    depth: usize,
    insts: &std::collections::HashMap<u32, &svn_analyze::ComponentInstantiation>,
) {
    match node {
        Node::EachBlock(b) => emit_each_block(out, source, b, depth, insts),
        Node::IfBlock(b) => {
            // Emit as a real `if/else if/else` chain so TS's control-flow
            // analysis narrows union / nullable / type-guard references
            // inside each arm. Without this, `{#if shape.kind === 'circle'}`
            // leaves `shape.radius` reading as "Property 'radius' does not
            // exist on type 'Shape'" inside the nested component-prop
            // check, and `{#if maybe}{...maybe...}{/if}` reads as "`maybe`
            // is possibly undefined". Conditions are wrapped in an extra
            // pair of parens to stay robust against operator-precedence
            // oddities in the raw source text.
            //
            // Immediately inside each branch we emit a `void [<ident>, …]`
            // statement listing every root identifier from the condition.
            // tsgo fires TS2774 ("this condition will always return true
            // since this function is always defined") on `&&` operands of
            // non-nullable function type — but the check is suppressed if
            // the same identifier symbol appears in the block body.
            // Svelte templates that poll a context object for component
            // references (`{#if editable && ctx.GhostButton}<ctx.GhostButton/>`)
            // tend to USE those references inside the block; the synthesized
            // list mirrors that usage when the user's body doesn't otherwise
            // reference every condition operand by value. Wrapping as a
            // plain array literal avoids re-introducing the `&&` chain that
            // triggered the check in the first place.
            let indent = "    ".repeat(depth);
            let main_cond = source
                .get(b.condition_range.start as usize..b.condition_range.end as usize)
                .unwrap_or("true")
                .trim();
            let _ = writeln!(out, "{indent}if (({main_cond})) {{");
            emit_condition_ref_marker(out, source, b.condition_range, depth + 1);
            emit_template_body(out, source, &b.consequent, depth + 1, insts);
            for arm in &b.elseif_arms {
                let arm_cond = source
                    .get(arm.condition_range.start as usize..arm.condition_range.end as usize)
                    .unwrap_or("true")
                    .trim();
                let _ = writeln!(out, "{indent}}} else if (({arm_cond})) {{");
                emit_condition_ref_marker(out, source, arm.condition_range, depth + 1);
                emit_template_body(out, source, &arm.body, depth + 1, insts);
            }
            if let Some(alt) = &b.alternate {
                let _ = writeln!(out, "{indent}}} else {{");
                emit_template_body(out, source, alt, depth + 1, insts);
            }
            let _ = writeln!(out, "{indent}}}");
        }
        Node::AwaitBlock(b) => {
            if let Some(p) = &b.pending {
                emit_template_body(out, source, p, depth, insts);
            }
            if let Some(t) = &b.then_branch {
                // `{:then v}` binds `v` to the resolved value for the
                // duration of the then-branch body. Declare each
                // identifier the context pattern destructures so
                // references inside the branch (component-prop checks,
                // each-blocks iterating over `v`, etc.) resolve. Walk
                // the body inside a fresh lexical scope so the binding
                // doesn't leak to sibling branches.
                emit_branch_with_binding(
                    out,
                    source,
                    t.context_range.as_ref(),
                    &t.body,
                    depth,
                    insts,
                );
            }
            if let Some(c) = &b.catch_branch {
                emit_branch_with_binding(
                    out,
                    source,
                    c.context_range.as_ref(),
                    &c.body,
                    depth,
                    insts,
                );
            }
        }
        Node::KeyBlock(b) => emit_template_body(out, source, &b.body, depth, insts),
        Node::SnippetBlock(b) => emit_snippet_block(out, source, b, depth, insts),
        Node::Element(e) => emit_template_body(out, source, &e.children, depth, insts),
        Node::Component(c) => emit_component_node(out, source, c, depth, insts),
        Node::SvelteElement(s) => emit_template_body(out, source, &s.children, depth, insts),
        Node::Interpolation(i) => emit_at_const_if_any(out, source, i, depth),
        Node::Text(_) | Node::Comment(_) => {}
    }
}

/// If `interp` is an `{@const <pattern> = <expr>}` tag, emit it inline
/// as a real `const <pattern> = <expr>;` statement in the current
/// template-check scope.
///
/// Without inline emission, the `@const`-declared name lives only as a
/// top-of-function `let NAME: any = undefined;` stub (see
/// `at_const_names` in the analyze crate). That works for "does the
/// name resolve?" checks but drops the expression's inferred type. A
/// pattern like
///     `{@const featureType = persistentFeature.settings.type}`
///     `{#if featureType === 'persistent-comment'}`
/// needs `featureType` to carry the discriminant literal type so TS's
/// control-flow analysis narrows it inside the `{#if}`. Emitting
/// inline pins the type. The top-level `let NAME: any` stub stays in
/// place so forward references (rare but possible) still resolve; the
/// inline `const` shadows it inside the block.
///
/// Destructured patterns (`{@const [a, { b }] = tuple}`) fall out for
/// free — we copy the source text verbatim and TS handles the pattern.
fn emit_at_const_if_any(
    out: &mut String,
    source: &str,
    interp: &svn_parser::Interpolation,
    depth: usize,
) {
    // Peek at the raw source for `{@const ` — the parser collapsed every
    // `{@*}` tag into an `Interpolation`, so we can't distinguish by
    // AST shape alone.
    let tag_start = interp.range.start as usize;
    let tag_end = interp.range.end as usize;
    let Some(full) = source.get(tag_start..tag_end) else {
        return;
    };
    let prefix = "{@const";
    if !full.starts_with(prefix) {
        return;
    }
    let after_prefix = &full[prefix.len()..];
    // Require a whitespace boundary after `@const` so we don't match a
    // hypothetical `{@constfoo ...}` token.
    if !after_prefix.starts_with(|c: char| c.is_ascii_whitespace()) {
        return;
    }
    // Body = expression_range (parser already trimmed the keyword).
    let body_start = interp.expression_range.start as usize;
    let body_end = interp.expression_range.end as usize;
    let Some(body) = source.get(body_start..body_end) else {
        return;
    };
    let body = body.trim();
    if body.is_empty() {
        return;
    }
    let indent = "    ".repeat(depth);
    // `const <pattern> = <expr>` — the body already carries `X = Y`
    // (pattern-or-name on the left of `=`, expression on the right).
    // Re-emitting inside the template-check `const` keyword pins the
    // inferred type so downstream `{#if NAME === '…'}` narrows.
    let _ = writeln!(out, "{indent}const {body};");

    // Void every binding introduced by the pattern. Without this tsgo
    // fires TS6133 ("declared but never read") on `@const` tags whose
    // binding isn't referenced elsewhere in the enclosing block —
    // which can happen when the user only uses the binding inside a
    // conditional branch that isn't taken in a given type narrowing,
    // or when the `@const` is a side-effect helper like `{@const _ =
    // track()}`. Scanning the pattern LHS is the minimal fix; the
    // real-runtime semantics treat `{@const}` as a reactive value so
    // users don't expect the "unused local" warning to fire.
    // Take everything up to the first top-level `=` as the binding
    // pattern. Inside destructure brackets/braces `=` is a default
    // value, not the initializer — so track depth. Also trim a
    // top-level type annotation (`foo: SomeType`) because emitting
    // `void SomeType` would fire TS2693 ("only refers to a type").
    let lhs = split_lhs(body);
    for name in collect_pattern_names(&lhs) {
        let _ = writeln!(out, "{indent}void {name};");
    }
}

/// Extract the binding-pattern prefix of an `{@const}` body, discarding
/// the type annotation and the initializer.
///
/// Examples:
///   - `foo = 1` → `foo`
///   - `foo: Record<A, B> = {}` → `foo`
///   - `[a, { b }] = tuple` → `[a, { b }]`
///   - `{ a = 1, b } = obj` → `{ a = 1, b }`
///
/// A top-level `:` terminates the pattern, preserving `:` inside
/// destructures (`{ key: binding }`). A top-level `=` outside any
/// brackets terminates the pattern. Depth-tracked so defaults and
/// nested types don't trip the scan.
fn split_lhs(body: &str) -> String {
    let bytes = body.as_bytes();
    let mut depth = 0i32;
    let mut end = bytes.len();
    let mut i = 0usize;
    while i < bytes.len() {
        match bytes[i] {
            b'{' | b'[' | b'(' | b'<' => depth += 1,
            b'}' | b']' | b')' | b'>' if depth > 0 => depth -= 1,
            b'=' if depth == 0 => {
                end = i;
                break;
            }
            b':' if depth == 0 => {
                end = i;
                break;
            }
            _ => {}
        }
        i += 1;
    }
    body[..end].trim().to_string()
}

/// Collect every identifier introduced by a (possibly destructuring)
/// binding pattern on the LHS of an `{@const}` tag.
///
/// Examples of what's collected:
///   - `foo` → [foo]
///   - `{ a, b: c, ...rest }` → [a, c, rest]
///   - `[a, { b }, ...rest]` → [a, b, rest]
///
/// Byte-scanning is enough for this lenient use — tsgo catches
/// anything we'd miss as a real diagnostic on the user's pattern, and
/// the only downstream consumer is `void <name>;` which is
/// forgiving.
fn collect_pattern_names(lhs: &str) -> Vec<String> {
    let mut out: Vec<String> = Vec::new();
    let bytes = lhs.as_bytes();
    let mut i = 0usize;
    // In object-pattern `{ key: value }`, the binding is on the RHS of
    // the colon; track that state.
    let mut after_colon = false;
    // Track whether the previous non-space char was a comma, opener,
    // or `...` — those positions are where a new binding starts in
    // array/object patterns.
    let mut at_binding_start = true;
    let mut depth = 0i32;

    while i < bytes.len() {
        let b = bytes[i];
        match b {
            b'{' | b'[' => {
                depth += 1;
                i += 1;
                at_binding_start = true;
                after_colon = false;
                continue;
            }
            b'}' | b']' => {
                depth -= 1;
                i += 1;
                after_colon = false;
                at_binding_start = false;
                continue;
            }
            b',' => {
                i += 1;
                at_binding_start = true;
                after_colon = false;
                continue;
            }
            b':' => {
                // `key: value` inside an object pattern — the next
                // ident is the binding, not the key.
                i += 1;
                after_colon = true;
                at_binding_start = false;
                continue;
            }
            b'=' if depth > 0 => {
                // Default value in a destructure (`{ a = 1 }`); skip
                // until the next `,` or closing brace.
                let mut paren_depth = 0i32;
                i += 1;
                while i < bytes.len() {
                    match bytes[i] {
                        b'(' | b'[' | b'{' => paren_depth += 1,
                        b')' | b']' | b'}' if paren_depth > 0 => paren_depth -= 1,
                        b',' | b'}' | b']' if paren_depth == 0 => break,
                        _ => {}
                    }
                    i += 1;
                }
                continue;
            }
            b'.' if i + 2 < bytes.len() && &bytes[i..i + 3] == b"..." => {
                // Rest element. The following ident is a binding.
                i += 3;
                at_binding_start = true;
                after_colon = false;
                continue;
            }
            b if b.is_ascii_whitespace() => {
                i += 1;
                continue;
            }
            _ => {}
        }
        // Identifier?
        if b.is_ascii_alphabetic() || b == b'_' || b == b'$' {
            let start = i;
            while i < bytes.len() {
                let c = bytes[i];
                if c.is_ascii_alphanumeric() || c == b'_' || c == b'$' {
                    i += 1;
                } else {
                    break;
                }
            }
            let is_top_level = depth == 0;
            let is_binding = if is_top_level {
                // Plain `const foo = ...` — the ident is the binding.
                true
            } else {
                // Inside a pattern. Peek past whitespace to the next
                // non-space char:
                //   `{ a, b }`       → ident followed by `,`/`}` → binding.
                //   `{ a: b }`       → ident followed by `:`     → KEY (not a binding).
                //                     The `b` after `:` (after_colon) is the binding.
                //   `{ a = 1 }`      → ident followed by `=`     → binding with default.
                //   `[a, b]`         → at_binding_start true     → binding.
                //   `...rest`        → at_binding_start set true → binding.
                let mut j = i;
                while j < bytes.len() && bytes[j].is_ascii_whitespace() {
                    j += 1;
                }
                let next = bytes.get(j).copied();
                if after_colon {
                    // `{ key: binding }` — the ident after `:` is always
                    // a binding unless the next char opens a nested
                    // pattern (handled separately by the `{`/`[` cases
                    // above).
                    true
                } else if at_binding_start {
                    // Ambiguity: object-pattern position could be either
                    // shorthand (`{ a }`, binding) or key-with-renamed
                    // binding (`{ a: b }`, key).
                    !matches!(next, Some(b':'))
                } else {
                    // Not at start, not after colon — not a binding.
                    false
                }
            };
            if is_binding {
                out.push(lhs[start..i].to_string());
            }
            at_binding_start = false;
            after_colon = false;
            continue;
        }
        // Anything else — reset markers and advance.
        at_binding_start = false;
        after_colon = false;
        i += 1;
    }
    out
}

/// Emit a `void [<access>, …];` statement listing every identifier /
/// property-access chain referenced inside the condition expression at
/// `range`. A no-op at runtime but a required pacifier for tsgo's
/// TS2774 check, which flags non-nullable-function operands of a
/// conditional `&&`/`||` chain unless the same symbol appears as a
/// value reference inside the enclosing block body.
///
/// We extract identifier chains (`foo`, `foo.bar`, `foo.bar.baz`) rather
/// than whole logical operands because re-emitting a comparison like
/// `displayMode !== 'full'` inside a block that already narrowed
/// `displayMode` to exclude `'full'` fires TS2367 ("this comparison
/// appears to be unintentional because the types have no overlap").
/// Identifier-chain references are narrowing-neutral and still satisfy
/// the check: `isSymbolUsedInConditionBody` walks identifiers in the
/// body and matches on property-access chains with the same symbol.
///
/// We skip negated (`!(…)`) conditions entirely: TS2774 doesn't fire
/// reliably when the condition lives behind `!`, and emitting a
/// property-access marker inside the negated branch can surface type
/// errors (TS18047 / TS2339) that the user's inverted narrowing would
/// normally make unreachable.
fn emit_condition_ref_marker(out: &mut String, source: &str, range: svn_core::Range, depth: usize) {
    let Some(cond_text) = source.get(range.start as usize..range.end as usize) else {
        return;
    };
    if cond_text.trim_start().starts_with('!') {
        return;
    }
    let chains = extract_property_chains(cond_text);
    if chains.is_empty() {
        return;
    }
    let indent = "    ".repeat(depth);
    out.push_str(&indent);
    out.push_str("void [");
    for (i, chain) in chains.iter().enumerate() {
        if i > 0 {
            out.push_str(", ");
        }
        out.push_str(chain);
    }
    out.push_str("];\n");
}

/// Extract every top-level identifier-or-property-access chain from
/// `text`, deduplicated and in source order. Skips string literals,
/// template literals, regex literals, comments, and anything inside
/// balanced parens / brackets / braces (so inner-scope bindings from an
/// arrow parameter list, object literal, or array literal don't leak
/// into the marker). Suppresses keywords and the Svelte auto-subscribe
/// `$ident` form (which isn't a real property reference).
///
/// Chain suffixes after an identifier (`.prop`, `?.prop`) are included
/// so `ctx.GhostButton` emits as a single ref. Call-expression argument
/// lists and property-access subscripts are skipped because re-emitting
/// them can introduce TS18047 / TS2339 from partial narrowing when the
/// enclosing block inverts the original condition (`{#if !(…)}`).
///
/// Examples:
/// - `editable && ctx.GhostButton && options.length < max` →
///   `editable`, `ctx.GhostButton`, `options.length`, `max`
/// - `messages.some((m) => m.role === 'x')` → `messages.some`
///   (contents of `(…)` ignored, so `m` / `m.role` don't leak)
fn extract_property_chains(text: &str) -> Vec<String> {
    let bytes = text.as_bytes();
    let mut out: Vec<String> = Vec::new();
    let mut seen: HashSet<String> = HashSet::new();
    let mut i = 0usize;

    while i < bytes.len() {
        let b = bytes[i];
        // Line comment.
        if b == b'/' && i + 1 < bytes.len() && bytes[i + 1] == b'/' {
            i += 2;
            while i < bytes.len() && bytes[i] != b'\n' {
                i += 1;
            }
            continue;
        }
        // Block comment.
        if b == b'/' && i + 1 < bytes.len() && bytes[i + 1] == b'*' {
            i += 2;
            while i + 1 < bytes.len() && !(bytes[i] == b'*' && bytes[i + 1] == b'/') {
                i += 1;
            }
            i = (i + 2).min(bytes.len());
            continue;
        }
        // String / template literals — entirely skipped (their
        // identifier refs rarely participate in the `&&` chain that
        // triggers TS2774).
        if b == b'\'' || b == b'"' {
            let quote = b;
            i += 1;
            while i < bytes.len() && bytes[i] != quote {
                if bytes[i] == b'\\' && i + 1 < bytes.len() {
                    i += 2;
                    continue;
                }
                i += 1;
            }
            i += 1;
            continue;
        }
        if b == b'`' {
            i += 1;
            while i < bytes.len() && bytes[i] != b'`' {
                if bytes[i] == b'\\' && i + 1 < bytes.len() {
                    i += 2;
                    continue;
                }
                if bytes[i] == b'$' && i + 1 < bytes.len() && bytes[i + 1] == b'{' {
                    i += 2;
                    let mut d = 1;
                    while i < bytes.len() && d > 0 {
                        match bytes[i] {
                            b'{' => d += 1,
                            b'}' => d -= 1,
                            _ => {}
                        }
                        if d > 0 {
                            i += 1;
                        }
                    }
                    if i < bytes.len() {
                        i += 1;
                    }
                    continue;
                }
                i += 1;
            }
            if i < bytes.len() {
                i += 1;
            }
            continue;
        }
        // Skip balanced parens / braces / brackets entirely — arguments,
        // arrow bodies, object/array literals don't participate in the
        // outer `&&` chain and their inner identifiers reference scoped
        // bindings (`messages.some((m) => m.role)` — `m` is an arrow
        // parameter, not a script binding). This keeps us from emitting
        // references to block-scoped names in the marker.
        if b == b'(' || b == b'[' || b == b'{' {
            let (open, close) = match b {
                b'(' => (b'(', b')'),
                b'[' => (b'[', b']'),
                _ => (b'{', b'}'),
            };
            i += 1;
            let mut d = 1i32;
            while i < bytes.len() && d > 0 {
                match bytes[i] {
                    x if x == open => d += 1,
                    x if x == close => d -= 1,
                    b'\'' | b'"' => {
                        let quote = bytes[i];
                        i += 1;
                        while i < bytes.len() && bytes[i] != quote {
                            if bytes[i] == b'\\' && i + 1 < bytes.len() {
                                i += 2;
                                continue;
                            }
                            i += 1;
                        }
                    }
                    _ => {}
                }
                if d > 0 {
                    i += 1;
                }
            }
            if i < bytes.len() {
                i += 1;
            }
            continue;
        }
        // Identifier start?
        if !is_ident_start_byte(b) {
            i += 1;
            continue;
        }
        // Previous non-whitespace byte: if it's `.`, we're in a property
        // position — skip; the containing chain has already captured
        // this identifier.
        let prev = previous_non_ws(bytes, i);
        if prev == Some(b'.') {
            i = skip_ident(bytes, i);
            continue;
        }
        // Start of a fresh chain. Walk forward through `.ident` and
        // `?.ident` segments. Bracket and call-argument suffixes are
        // NOT swallowed so a call expression like `f(x)` yields just
        // `f`, matching the existing template-refs pass convention.
        let chain_start = i;
        i = skip_ident(bytes, i);
        loop {
            let mut j = i;
            while j < bytes.len() && bytes[j].is_ascii_whitespace() {
                j += 1;
            }
            if j >= bytes.len() {
                break;
            }
            // `.ident`
            if bytes[j] == b'.' && j + 1 < bytes.len() && is_ident_start_byte(bytes[j + 1]) {
                i = skip_ident(bytes, j + 1);
                continue;
            }
            // `?.ident`
            if bytes[j] == b'?'
                && j + 2 < bytes.len()
                && bytes[j + 1] == b'.'
                && is_ident_start_byte(bytes[j + 2])
            {
                i = skip_ident(bytes, j + 2);
                continue;
            }
            break;
        }
        let chain = text[chain_start..i].trim();
        if chain.is_empty() {
            continue;
        }
        // Filter identifier-only chains that are keywords or the
        // auto-subscribe `$ident` shorthand (handled separately by the
        // store-ref pass).
        let looks_like_keyword = !chain.contains('.') && is_keyword_or_special(chain);
        if looks_like_keyword {
            continue;
        }
        let key = chain.to_string();
        if seen.insert(key.clone()) {
            out.push(key);
        }
    }
    out
}

#[inline]
fn is_ident_start_byte(b: u8) -> bool {
    b.is_ascii_alphabetic() || b == b'_' || b == b'$'
}

#[inline]
fn is_ident_continue_byte(b: u8) -> bool {
    b.is_ascii_alphanumeric() || b == b'_' || b == b'$'
}

fn skip_ident(bytes: &[u8], start: usize) -> usize {
    let mut i = start;
    while i < bytes.len() && is_ident_continue_byte(bytes[i]) {
        i += 1;
    }
    i
}

fn previous_non_ws(bytes: &[u8], i: usize) -> Option<u8> {
    let mut j = i;
    while j > 0 {
        j -= 1;
        if !bytes[j].is_ascii_whitespace() {
            return Some(bytes[j]);
        }
    }
    None
}

/// Keywords and reserved identifiers that should never appear in a
/// ref-marker void-array. Mirrors the filter in `template_refs` so a
/// condition like `{#if typeof x === 'string'}` doesn't emit a stray
/// `typeof` reference.
fn is_keyword_or_special(s: &str) -> bool {
    matches!(
        s,
        "true"
            | "false"
            | "null"
            | "undefined"
            | "this"
            | "void"
            | "typeof"
            | "new"
            | "instanceof"
            | "in"
            | "of"
            | "as"
            | "let"
            | "const"
            | "var"
            | "function"
            | "if"
            | "else"
            | "for"
            | "while"
            | "do"
            | "return"
            | "yield"
            | "await"
            | "async"
            | "delete"
            | "throw"
            | "try"
            | "catch"
            | "finally"
            | "switch"
            | "case"
            | "default"
            | "break"
            | "continue"
            | "class"
            | "extends"
            | "super"
            | "import"
            | "export"
            | "from"
            | "satisfies"
    ) || s.starts_with('$')
}

/// Emit a `for`-of loop for an `{#each}` block.
///
/// `{#each items}` without an `as` clause is legal Svelte (iterate N times,
/// discard the value); we use `__svn_each_unused` as a placeholder binding
/// so the emitted TypeScript stays syntactically valid.
fn emit_each_block(
    out: &mut String,
    source: &str,
    b: &EachBlock,
    depth: usize,
    insts: &std::collections::HashMap<u32, &svn_analyze::ComponentInstantiation>,
) {
    let indent = "    ".repeat(depth);
    let expr_text = source
        .get(b.expression_range.start as usize..b.expression_range.end as usize)
        .unwrap_or("undefined")
        .trim();
    let binding_text = match &b.as_clause {
        Some(c) => source
            .get(c.context_range.start as usize..c.context_range.end as usize)
            .unwrap_or("__svn_each_unused")
            .to_string(),
        None => "__svn_each_unused".to_string(),
    };
    // `{#each items as item, i}` — `i` is the zero-based iteration index.
    // `__svn_each_items` returns a plain Iterable, which doesn't expose
    // `.entries()`, so declaring the index as a `const i: number` inside
    // the loop body is simpler than rewriting the for-of pattern to
    // destructure an [index, item] pair. Using `0` for the value is a
    // type-only trick — the generated function is never executed.
    let index_binding: Option<&str> = b
        .as_clause
        .as_ref()
        .and_then(|c| c.index_range)
        .and_then(|r| source.get(r.start as usize..r.end as usize));
    let _ = writeln!(
        out,
        "{indent}for (const {binding_text} of __svn_each_items({expr_text})) {{"
    );
    if let Some(ix) = index_binding {
        let _ = writeln!(out, "{indent}    const {ix}: number = 0;");
    }
    emit_template_body(out, source, &b.body, depth + 1, insts);
    // Void every identifier that the binding pattern destructures, not
    // just the first. `[id, label]` and `[id, { label }]` both bind two
    // names and TS6133 fires on each unused one.
    for ident in all_identifiers(&binding_text) {
        let _ = writeln!(out, "{indent}    void {ident};");
    }
    if let Some(ix) = index_binding {
        let _ = writeln!(out, "{indent}    void {ix};");
    }
    let _ = writeln!(out, "{indent}}}");

    if let Some(alt) = &b.alternate {
        emit_template_body(out, source, alt, depth, insts);
    }
}

/// Walk `{:then v}` / `{:catch e}` body in a fresh lexical scope that
/// declares the branch's context binding as `any`. Without the
/// declaration, references to the bound name inside the branch (a
/// component-prop check that passes `v` as a prop, a subsequent
/// `{#each v as item}`) fire TS2304.
///
/// Supports destructure patterns (`{:then { a, b }}`, `{:then [x]}`)
/// via `all_identifiers`. An absent context range (`{:then}` with no
/// binding) skips the scope and just walks the body inline.
fn emit_branch_with_binding(
    out: &mut String,
    source: &str,
    context_range: Option<&svn_core::Range>,
    body: &Fragment,
    depth: usize,
    insts: &std::collections::HashMap<u32, &svn_analyze::ComponentInstantiation>,
) {
    let Some(range) = context_range else {
        emit_template_body(out, source, body, depth, insts);
        return;
    };
    let binding_text = source
        .get(range.start as usize..range.end as usize)
        .unwrap_or("")
        .trim();
    if binding_text.is_empty() {
        emit_template_body(out, source, body, depth, insts);
        return;
    }
    let idents = all_identifiers(binding_text);
    let indent = "    ".repeat(depth);
    let _ = writeln!(out, "{indent}{{");
    for ident in &idents {
        let _ = writeln!(out, "{indent}    const {ident}: any = undefined;");
    }
    emit_template_body(out, source, body, depth + 1, insts);
    for ident in &idents {
        let _ = writeln!(out, "{indent}    void {ident};");
    }
    let _ = writeln!(out, "{indent}}}");
}

/// Emit a lexical-scope block wrapping a `{#snippet name(params)}` body
/// so the snippet's parameter identifiers are in scope for references
/// inside the body (including component-prop checks on `<Component>`
/// nodes nested below the snippet).
///
/// Parameters are typed as `any` — we don't resolve their types from
/// the declared `Snippet<[...]>` shape here. For excess-prop and
/// "cannot find name" detection that's sufficient; precise param
/// typing would require threading the consumer's `Snippet<...>` into
/// the snippet body's type context, which v0.1 punts on.
///
/// Handles both identifier params (`foo, bar`) and destructure params
/// (`{months, weekdays}`, `[a, b]`) via `all_identifiers`. Default
/// values (`foo = 1`) have the default expression stripped before
/// identifier extraction.
fn emit_snippet_block(
    out: &mut String,
    source: &str,
    b: &SnippetBlock,
    depth: usize,
    insts: &std::collections::HashMap<u32, &svn_analyze::ComponentInstantiation>,
) {
    let indent = "    ".repeat(depth);
    let params_text = source
        .get(b.parameters_range.start as usize..b.parameters_range.end as usize)
        .unwrap_or("")
        .trim();
    // `{#snippet name()}` with an empty parameter list — skip the
    // scope + placeholder binding entirely. `all_identifiers` never
    // returns an empty vec (it falls back to `__svn_each_unused`),
    // so we intercept the empty-params case before calling it.
    if params_text.is_empty() {
        emit_template_body(out, source, &b.body, depth, insts);
        return;
    }
    // Open a fresh block, then reference the ORIGINAL params text
    // inside an arrow function's signature — that keeps the user's
    // type annotations (e.g. `MouseEventHandler<HTMLButtonElement>`)
    // bound as references. Without this, types only used in a
    // snippet parameter list (and never in the script body) fire
    // TS6133 "declared but never read" on their import.
    //
    // We don't try to thread contextual typing through — top-level
    // snippets have no parent satisfies target to flow from. Each
    // user-named parameter gets re-declared inside the body as `const
    // <name>: any` so the snippet body type-checks without depending
    // on the arrow's inferred param types (which the `null as any`
    // cast erases anyway).
    let annotated = annotate_snippet_params(params_text);
    let idents = all_identifiers(params_text);
    // Emit the body INSIDE a no-op arrow function expression whose
    // params carry the user's type annotations. This serves two
    // purposes simultaneously:
    //   1. The arrow params are the binding introductions — their
    //      type annotations flow into the body, so a snippet like
    //      `{#snippet state(state: VideoState)}` gets `state: VideoState`
    //      bindings rather than `state: any`.
    //   2. Any type imported solely for a snippet param annotation
    //      (e.g. `MouseEventHandler<HTMLButtonElement>`) shows up as
    //      a reference in the emitted code, suppressing TS6133.
    //
    // We use a function *expression* (not a type) so default values
    // and optional-after-required orderings remain legal.
    let _ = writeln!(out, "{indent}{{");
    let _ = writeln!(out, "{indent}    void (({annotated}) => {{");
    emit_template_body(out, source, &b.body, depth + 2, insts);
    for ident in &idents {
        let _ = writeln!(out, "{indent}        void {ident};");
    }
    let _ = writeln!(out, "{indent}    }});");
    let _ = writeln!(out, "{indent}}}");
}

/// Emit `let __svn_action_attrs_N: any = {};` declarations inside
/// `__svn_tpl_check` — one per `use:` directive — and immediately void
/// each one so TypeScript's `noUnusedLocals` doesn't flag them.
///
/// The void in the *outer* function (in `emit_void_block`) brings the
/// names into scope for whoever might reference them externally; the void
/// here suppresses TS6133 inside `__svn_tpl_check` itself, where the
/// declaration lives.
fn emit_action_attrs_declarations(out: &mut String, summary: &TemplateSummary) {
    for name in summary.void_refs.names() {
        if name.starts_with("__svn_action_attrs_") {
            let _ = writeln!(out, "        let {name}: any = {{}};");
            let _ = writeln!(out, "        void {name};");
        }
    }
}

/// Emit a `<Component ...>` node as a call to the component's typed
/// default export:
///
/// ```ts
///     ComponentRoot(__svn_any(), {
///         prop1: "lit",
///         prop2: (expr),
///         prop3,
///         prop4: true,
///         snippetName: (params) => {
///             <snippet body>
///             return __svn_snippet_return();
///         },
///     });
/// ```
///
/// The callable shape is what makes TypeScript's contextual typing
/// work here. The component's `.svelte.ts` overlay exports a
/// `declare function __svn_component_default(anchor, props: Props)`;
/// each prop slot's declared type flows into the consumer's expression
/// at this call site. Callback props destructure the right parameter
/// types (`onchange={({ checked }) => ...}` binds `checked: boolean`
/// instead of implicit-any), snippet props pick up `Snippet<[...]>`
/// contextual types for their arrow parameters, and excess properties
/// fire TS2353 thanks to object-literal inference strictness.
///
/// Directive-attached props (`bind:value`, `on:click`, `use:action`,
/// `class:active`, etc.) and spreads are skipped at analyze time — they
/// don't contribute to the callable's props argument. `__svn_any()`
/// returns a fresh `any`; the first argument slot simulates Svelte's
/// mount-anchor parameter without constraining inference.
///
/// Non-snippet children (text, elements, nested components, blocks) are
/// walked AFTER the call-site scaffolding in the component's own scope.
/// Direct-child `{#snippet name(params)}` blocks ARE consumed as props
/// on the object literal — not walked a second time — so their param
/// destructures pick up contextual types from the parent's Snippet prop
/// shape instead of reading as implicit-any.
fn emit_component_node(
    out: &mut String,
    source: &str,
    c: &svn_parser::Component,
    depth: usize,
    insts: &std::collections::HashMap<u32, &svn_analyze::ComponentInstantiation>,
) {
    let snippet_children: Vec<&SnippetBlock> = c
        .children
        .nodes
        .iter()
        .filter_map(|n| match n {
            Node::SnippetBlock(b) => Some(b),
            _ => None,
        })
        .collect();

    // Only emit the call when analyze collected an instantiation for
    // this node. Components disqualified at analyze time (e.g.
    // multi-part interpolated attribute values) fall back to a plain
    // template-body walk so snippet hoists still emit there.
    let inst = insts.get(&c.range.start);
    if let Some(inst) = inst {
        emit_component_call(out, source, inst, depth, &snippet_children, insts);
    }

    if inst.is_none() || snippet_children.is_empty() {
        emit_template_body(out, source, &c.children, depth, insts);
        return;
    }
    // Snippet children consumed as props above — walk the rest.
    for node in &c.children.nodes {
        if matches!(node, Node::SnippetBlock(_)) {
            continue;
        }
        emit_template_node(out, source, node, depth, insts);
    }
}

/// Emit the call-site scaffolding for one component instantiation as
///
///     { const $$_CN = __svn_ensure_component(Comp);
///       new $$_CN({ target: __svn_any(), props: { ... } }); }
///
/// — the wrapper + local + `new` form chosen so a single emission
/// handles both our overlay-declared class defaults and third-party
/// `extends SvelteComponent` classes (and bare `Component<Props>`
/// values from user-typed contexts). The intermediate local is what
/// makes generic components' `<T>` resolve at the `new` site — TS
/// binds the construct signature's generics against the concrete prop
/// values there, not at the `__svn_ensure_component` site. See
/// design/phase_a/DESIGN.md for the validation.
///
/// Each instantiation gets its own block scope `{ ... }` so the
/// synthesized `$$_CN` local is siloed from sibling instantiations —
/// avoids shadowing / redeclaration when the same parent fragment
/// contains multiple components.
fn emit_component_call(
    out: &mut String,
    source: &str,
    inst: &svn_analyze::ComponentInstantiation,
    depth: usize,
    snippet_children: &[&SnippetBlock],
    insts: &std::collections::HashMap<u32, &svn_analyze::ComponentInstantiation>,
) {
    let indent = "    ".repeat(depth);
    let inner = "    ".repeat(depth + 1);
    let comp = &inst.component_root;
    // Per-call-site synthesized local. Using the instantiation's byte
    // offset keeps each one unique without threading a counter through
    // the walker.
    let local = format!("__svn_C_{:x}", inst.node_start);

    let _ = writeln!(out, "{indent}{{");
    let _ = writeln!(
        out,
        "{inner}const {local} = __svn_ensure_component({comp});"
    );

    if snippet_children.is_empty() && inst.props.is_empty() {
        let _ = writeln!(
            out,
            "{inner}new {local}({{ target: __svn_any(), props: {{}} }});"
        );
        let _ = writeln!(out, "{indent}}}");
        return;
    }

    if snippet_children.is_empty() {
        let _ = write!(out, "{inner}new {local}({{ target: __svn_any(), props: {{");
        let mut first = true;
        for p in &inst.props {
            if !first {
                let _ = write!(out, ", ");
            }
            first = false;
            write_prop_shape(out, source, p);
        }
        let _ = writeln!(out, "}} }});");
        let _ = writeln!(out, "{indent}}}");
        return;
    }

    // Multi-line form with snippets-as-arrow-props.
    let _ = writeln!(out, "{inner}new {local}({{");
    let opts_inner = "    ".repeat(depth + 2);
    let props_inner = "    ".repeat(depth + 3);
    let _ = writeln!(out, "{opts_inner}target: __svn_any(),");
    let _ = writeln!(out, "{opts_inner}props: {{");
    for p in &inst.props {
        out.push_str(&props_inner);
        write_prop_shape(out, source, p);
        let _ = writeln!(out, ",");
    }
    for s in snippet_children {
        out.push_str(&props_inner);
        write_snippet_arrow_prop(out, source, s, depth + 3, insts);
        let _ = writeln!(out, ",");
    }
    let _ = writeln!(out, "{opts_inner}}},");
    let _ = writeln!(out, "{inner}}});");
    let _ = writeln!(out, "{indent}}}");
}

/// Write a single property of a component-prop-check object literal,
/// dispatching on the analyze-side `PropShape` variant.
fn write_prop_shape(out: &mut String, source: &str, p: &svn_analyze::PropShape) {
    match p {
        svn_analyze::PropShape::Literal { name, value } => {
            write_object_key(out, name);
            out.push_str(": ");
            write_js_string_literal(out, value);
        }
        svn_analyze::PropShape::Expression { name, expr_range } => {
            let expr = &source[expr_range.start as usize..expr_range.end as usize];
            write_object_key(out, name);
            let _ = write!(out, ": ({expr})");
        }
        svn_analyze::PropShape::Shorthand { name } => {
            // `{foo}` shorthand is only valid when the key is also a
            // valid JS identifier — otherwise expand to `"foo": foo`.
            if is_simple_js_identifier(name) {
                out.push_str(name);
            } else {
                write_object_key(out, name);
                let _ = write!(out, ": {name}");
            }
        }
        svn_analyze::PropShape::BoolShorthand { name } => {
            write_object_key(out, name);
            out.push_str(": true");
        }
    }
}

/// Split `params_text` on top-level commas and, for each part that
/// doesn't already carry a top-level type annotation, append `: any`.
/// "Top-level" here means depth 0 in balanced `()`, `[]`, `{}`, `<>` —
/// so object-destructure patterns like `{ a, b }` are treated as one
/// unannotated part (inner `:` colons are inside braces) and get
/// `{ a, b }: any` appended.
///
/// Used only by top-level `{#snippet}` blocks whose params have no
/// parent `Snippet<[...]>` contextual type to flow from. Snippets
/// consumed as direct children of a `<Component>` go through
/// `write_snippet_arrow_prop`, which uses the parent's declared prop
/// type via the callable component shape and therefore doesn't need
/// explicit `: any` annotations.
fn annotate_snippet_params(params_text: &str) -> String {
    let bytes = params_text.as_bytes();
    let mut parts: Vec<(usize, usize)> = Vec::new();
    let mut depth = 0i32;
    let mut start = 0;
    for (i, &b) in bytes.iter().enumerate() {
        match b {
            b'(' | b'[' | b'{' | b'<' => depth += 1,
            b')' | b']' | b'}' | b'>' if depth > 0 => depth -= 1,
            b',' if depth == 0 => {
                parts.push((start, i));
                start = i + 1;
            }
            _ => {}
        }
    }
    parts.push((start, bytes.len()));

    let mut out = String::with_capacity(params_text.len() + 16);
    let mut first = true;
    for (s, e) in parts {
        if !first {
            out.push_str(", ");
        }
        first = false;
        let part = params_text[s..e].trim();
        if part.is_empty() {
            continue;
        }
        let part_bytes = part.as_bytes();
        let mut d = 0i32;
        let mut has_top_colon = false;
        for &b in part_bytes {
            match b {
                b'(' | b'[' | b'{' | b'<' => d += 1,
                b')' | b']' | b'}' | b'>' if d > 0 => d -= 1,
                b':' if d == 0 => {
                    has_top_colon = true;
                    break;
                }
                _ => {}
            }
        }
        out.push_str(part);
        if !has_top_colon {
            if let Some(eq) = find_top_level_eq(part) {
                let before = part[..eq].trim_end();
                let after = &part[eq..];
                out.truncate(out.len() - part.len());
                out.push_str(before);
                out.push_str(": any ");
                out.push_str(after);
            } else {
                out.push_str(": any");
            }
        }
    }
    out
}

/// First top-level `=` in `s`, or `None`. Skips `==` / `===` / `=>`.
fn find_top_level_eq(s: &str) -> Option<usize> {
    let bytes = s.as_bytes();
    let mut d = 0i32;
    for (i, &b) in bytes.iter().enumerate() {
        match b {
            b'(' | b'[' | b'{' | b'<' => d += 1,
            b')' | b']' | b'}' | b'>' if d > 0 => d -= 1,
            b'=' if d == 0 => {
                let next = bytes.get(i + 1).copied();
                if next == Some(b'=') || next == Some(b'>') {
                    continue;
                }
                return Some(i);
            }
            _ => {}
        }
    }
    None
}

/// Write a `{#snippet name(params)}...{/snippet}` block as an
/// arrow-callback property value on the parent component's call-site
/// props object:
///
/// ```ts
///     name: (params) => {
///         <snippet body>
///         return __svn_snippet_return();
///     }
/// ```
///
/// The parameter text is spliced verbatim from the source — that
/// preserves user-provided type annotations, destructure patterns, and
/// default values. TypeScript's contextual typing reads the parent
/// component's declared `Snippet<[...]>` parameter shape through the
/// call signature's props slot and flows each tuple element into the
/// matching arrow parameter, so destructured snippet params pick up
/// real types instead of implicit-any. Parents that type their snippet
/// prop as `Snippet<[any]>` (or parents with no type annotation at all)
/// produce `any`-typed params, which is the correct "silently accept"
/// degradation.
///
/// No more per-parameter `: any` injection. The old satisfies-shape
/// lost the contextual type through `Partial<ComponentProps<typeof X>>`
/// extraction, forcing us to explicitly annotate each param. The
/// callable shape flows the type directly, so a user-written
/// `(x: string)` or an un-annotated `(item)` both type correctly.
///
/// `__svn_snippet_return()` returns `any`, which structurally satisfies
/// the opaque branded return type Svelte's `Snippet<[...]>` expects.
/// The closing `}` is written without a trailing newline so the caller
/// can append `,\n` at the property-value column.
fn write_snippet_arrow_prop(
    out: &mut String,
    source: &str,
    s: &SnippetBlock,
    depth: usize,
    insts: &std::collections::HashMap<u32, &svn_analyze::ComponentInstantiation>,
) {
    let indent = "    ".repeat(depth);
    let body_indent = "    ".repeat(depth + 1);
    let params_text = source
        .get(s.parameters_range.start as usize..s.parameters_range.end as usize)
        .unwrap_or("")
        .trim();
    write_object_key(out, &s.name);
    if params_text.is_empty() {
        let _ = writeln!(out, ": () => {{");
        emit_template_body(out, source, &s.body, depth + 1, insts);
        let _ = writeln!(out, "{body_indent}return __svn_snippet_return();");
        let _ = write!(out, "{indent}}}");
        return;
    }
    let _ = writeln!(out, ": ({params_text}) => {{");
    emit_template_body(out, source, &s.body, depth + 1, insts);
    for ident in all_identifiers(params_text) {
        let _ = writeln!(out, "{body_indent}void {ident};");
    }
    let _ = writeln!(out, "{body_indent}return __svn_snippet_return();");
    let _ = write!(out, "{indent}}}");
}

/// Write an object-literal key. Plain JS identifiers are emitted bare;
/// anything with a hyphen, a non-ident character, or a JS reserved
/// word lookalike is double-quoted (always safe).
fn write_object_key(out: &mut String, name: &str) {
    if is_simple_js_identifier(name) {
        out.push_str(name);
    } else {
        write_js_string_literal(out, name);
    }
}

/// True for ASCII identifiers `[A-Za-z_$][A-Za-z0-9_$]*`. We don't try
/// to enumerate JS reserved words — modern JS (ES5+) allows reserved
/// words as bare property names anyway.
fn is_simple_js_identifier(s: &str) -> bool {
    let mut chars = s.chars();
    let Some(first) = chars.next() else {
        return false;
    };
    if !(first.is_ascii_alphabetic() || first == '_' || first == '$') {
        return false;
    }
    chars.all(|c| c.is_ascii_alphanumeric() || c == '_' || c == '$')
}

/// Write `value` as a JS double-quoted string literal, escaping the
/// usual unsafe characters. Pure ASCII assumption — Svelte attribute
/// values are decoded earlier in the pipeline.
fn write_js_string_literal(out: &mut String, value: &str) {
    out.push('"');
    for c in value.chars() {
        match c {
            '"' => out.push_str("\\\""),
            '\\' => out.push_str("\\\\"),
            '\n' => out.push_str("\\n"),
            '\r' => out.push_str("\\r"),
            '\t' => out.push_str("\\t"),
            c if (c as u32) < 0x20 => {
                let _ = write!(out, "\\u{:04x}", c as u32);
            }
            c => out.push(c),
        }
    }
    out.push('"');
}

/// Emit getter/setter tuple placeholders for `bind:foo={getter, setter}`.
/// Same pattern as action-attrs: declare + void inside `__svn_tpl_check`.
fn emit_bind_pair_declarations(out: &mut String, summary: &TemplateSummary) {
    for name in summary.void_refs.names() {
        if name.starts_with("__svn_bind_pair_") {
            let _ = writeln!(
                out,
                "        let {name}: [() => any, (v: any) => void] = [() => undefined as any, () => {{}}];"
            );
            let _ = writeln!(out, "        void {name};");
        }
    }
}

fn emit_void_block(
    out: &mut String,
    summary: &TemplateSummary,
    store_refs: &[SmolStr],
    prop_names: &[SmolStr],
    template_refs: &[SmolStr],
    exported_locals: &[SmolStr],
) {
    // One `void <name>;` statement per synthesized name — NOT a single
    // `void (a, b, c);` block. The block form uses comma operators which
    // TypeScript flags with TS2695 ("Left side of comma operator is
    // unused and has no side effects"). Per-statement form has no such
    // problem and matches what upstream svelte-check does.
    //
    // Names covered:
    //   - the template-check wrapper (`__svn_tpl_check`)
    //   - store auto-subscribe aliases
    //   - destructured props (the component's public API; treat as used
    //     even if the body doesn't reference them directly)
    //   - script-declared bindings that are referenced from the template
    //     (component imports, locals only used in markup)
    //
    // NOT covered here (intentionally): `__svn_action_attrs_N` and
    // `__svn_bind_pair_N`. Those names are declared *inside* the inner
    // `__svn_tpl_check` function and self-voided there. Voiding them in
    // the outer scope as well would fire TS2304 (cannot find name) since
    // the inner declarations aren't visible from the outer function.
    let mut emitted: HashSet<String> = HashSet::new();
    let mut emit = |out: &mut String, name: &str| {
        if emitted.insert(name.to_string()) {
            let _ = writeln!(out, "    void {name};");
        }
    };
    for name in summary.void_refs.names() {
        if name.starts_with("__svn_action_attrs_") || name.starts_with("__svn_bind_pair_") {
            continue;
        }
        emit(out, name);
    }
    for name in store_refs {
        emit(out, name);
        // The auto-subscribe alias `$store` references the store, but the
        // underlying `store` const is itself only used in template
        // expressions like `$store` (which the alias receives). Void the
        // base name so TS6133 doesn't fire on the original declaration.
        if let Some(base) = name.strip_prefix('$') {
            emit(out, base);
        }
    }
    for name in prop_names {
        emit(out, name);
    }
    for name in template_refs {
        emit(out, name);
    }
    // Names declared `export const|let|var|function|class` (or
    // `export { x }`) by the user. Stripping the `export` keyword leaves
    // them as plain locals — without voiding, TS6133 fires on the
    // declaration. The user explicitly marked them as public surface so
    // counting them as "used" is the right call.
    for name in exported_locals {
        emit(out, name);
    }
}

/// Pull every identifier-like token out of a destructuring pattern.
///
/// For `id`             → `["id"]`
/// For `[id, label]`    → `["id", "label"]`
/// For `[id, { label }]` → `["id", "label"]`
/// For `{ a: x, b }`    → `["x", "b"]` (only the local-name side of `key:value`)
///
/// Best-effort byte scan — the analyze crate has a real oxc-backed
/// destructuring walk for the *script* path; this helper handles the
/// far smaller set of shapes that appear inside `{#each ... as <pat>}`
/// without the cost of an oxc invocation per each-block.
///
/// Falls back to a single `__svn_each_unused` token when nothing
/// identifier-shaped is found, so the emitted `void` line stays valid.
fn all_identifiers(binding: &str) -> Vec<String> {
    let bytes = binding.as_bytes();
    let mut out: Vec<String> = Vec::new();
    let mut i = 0;
    let mut depth_brace = 0usize; // tracks `{ ... }` for object key:value
    while i < bytes.len() {
        let b = bytes[i];
        match b {
            b'{' => {
                depth_brace += 1;
                i += 1;
            }
            b'}' => {
                depth_brace = depth_brace.saturating_sub(1);
                i += 1;
            }
            b'?' if depth_brace == 0 => {
                // Optional-parameter marker in TS snippet params: `name?:
                // Type`. No-op; the following `:` handles the type skip.
                // Each-block `as` clauses don't use `?`, so this branch
                // is inert for that caller.
                i += 1;
            }
            b':' if depth_brace == 0 => {
                // Top-level `:` on a snippet parameter introduces a TS
                // type annotation (`name: Foo<Bar>`). Skip until the
                // next top-level `,` — tracking paren/bracket/brace/
                // angle nesting so commas inside `Array<A, B>` or
                // `(a: X) => Y` don't terminate the annotation early.
                // Each-block `as` clauses never hit this (Svelte grammar
                // forbids type annotations on destructure targets).
                i += 1;
                let mut depth = 0usize;
                while i < bytes.len() {
                    match bytes[i] {
                        b'(' | b'[' | b'{' | b'<' => depth += 1,
                        b')' | b']' | b'}' | b'>' if depth > 0 => depth -= 1,
                        b',' if depth == 0 => break,
                        _ => {}
                    }
                    i += 1;
                }
            }
            b'=' => {
                // Skip default value `name = expr` — advance past expr to
                // the next comma/closer at the same depth. Conservative:
                // just stop collecting until we see `,` `]` `}`.
                i += 1;
                let mut paren = 0usize;
                while i < bytes.len() {
                    match bytes[i] {
                        b'(' | b'[' | b'{' => paren += 1,
                        b')' | b']' | b'}' if paren > 0 => paren -= 1,
                        b',' | b']' | b'}' if paren == 0 => break,
                        _ => {}
                    }
                    i += 1;
                }
            }
            _ if b.is_ascii_alphabetic() || b == b'_' || b == b'$' => {
                let start = i;
                while i < bytes.len() {
                    let c = bytes[i];
                    if c.is_ascii_alphanumeric() || c == b'_' || c == b'$' {
                        i += 1;
                    } else {
                        break;
                    }
                }
                let name = &binding[start..i];
                let take = if depth_brace > 0 {
                    // Inside an object pattern: `key: local` — only collect
                    // the local. `{ a }` shorthand has no colon so `a`
                    // counts. Look ahead: if the next non-ws byte is `:`,
                    // this identifier is a key and must be skipped;
                    // otherwise it is a binding (either the local after
                    // a colon, or a shorthand entry).
                    let mut j = i;
                    while j < bytes.len() && bytes[j].is_ascii_whitespace() {
                        j += 1;
                    }
                    bytes.get(j) != Some(&b':')
                } else {
                    true
                };
                if take {
                    out.push(name.to_string());
                }
            }
            _ => {
                i += 1;
            }
        }
    }
    if out.is_empty() {
        out.push("__svn_each_unused".to_string());
    }
    out
}

/// Rewrite `let <name>: T;` → `let <name>!: T;` for each bind-target
/// identifier, in-place inside the already-built output buffer.
///
/// Svelte assigns a `bind:this` target asynchronously, after the binding
/// element mounts. TypeScript's flow analysis can't see that, so any
/// closure reading the variable would be flagged "used before being
/// assigned" (TS2454). The `!:` definite-assignment assertion tells
/// TypeScript to trust us.
///
/// Only matches `let <name>:` patterns with the colon — declarations with
/// initializers (`let x = ...`) are already definitely assigned and don't
/// need the `!`. Adding `!` to an initialized declaration is itself a TS
/// error (TS1263).
fn rewrite_definite_assignment_in_place(out: &mut String, target_names: &[SmolStr]) {
    if target_names.is_empty() {
        return;
    }
    let original = std::mem::take(out);
    let bytes = original.as_bytes();
    let mut i = 0;
    while i < bytes.len() {
        if let Some(end) = try_match_let_decl(bytes, i, target_names) {
            out.push_str(&original[i..end]);
            out.push('!');
            i = end;
        } else {
            let ch_len = utf8_char_len(bytes[i]);
            out.push_str(&original[i..i + ch_len]);
            i += ch_len;
        }
    }
}

/// At byte position `i`, try to match `let <name>` where `<name>` is one
/// of `target_names` AND is followed by `:` (after optional whitespace)
/// AND has NO `=` initializer before the next `;` or newline (TS1263:
/// "Declarations with initializers cannot also have definite assignment
/// assertions"). Returns the byte position immediately after the matched
/// name on success.
fn try_match_let_decl(bytes: &[u8], i: usize, target_names: &[SmolStr]) -> Option<usize> {
    if i + 3 > bytes.len() || &bytes[i..i + 3] != b"let" {
        return None;
    }
    if i > 0 && is_ident_byte(bytes[i - 1]) {
        return None;
    }
    let after_let = i + 3;
    if after_let >= bytes.len() || !is_ascii_ws(bytes[after_let]) {
        return None;
    }
    let mut p = after_let;
    while p < bytes.len() && is_ascii_ws(bytes[p]) {
        p += 1;
    }
    let name_start = p;
    while p < bytes.len() && is_ident_byte(bytes[p]) {
        p += 1;
    }
    let name_end = p;
    if name_end == name_start {
        return None;
    }
    let name = &bytes[name_start..name_end];
    if !target_names.iter().any(|t| t.as_bytes() == name) {
        return None;
    }
    let mut q = name_end;
    while q < bytes.len() && is_ascii_ws(bytes[q]) {
        q += 1;
    }
    if q >= bytes.len() || bytes[q] != b':' {
        return None;
    }
    // Walk forward through the type annotation looking for `=` (= initializer)
    // before `;` or newline. Tracks `<>{}[]()` depth so generic args like
    // `Foo<T = U>` and object types like `{ k: V }` don't trigger false hits.
    // Skips `=>` (arrow function types) and `==`/`===` (equality operators
    // in conditional types) — none of those start an initializer.
    let mut s = q + 1;
    let mut paren_depth: i32 = 0;
    while s < bytes.len() {
        let c = bytes[s];
        match c {
            b'(' | b'[' | b'{' | b'<' => paren_depth += 1,
            b')' | b']' | b'}' | b'>' => paren_depth -= 1,
            b'=' if paren_depth == 0 => {
                let next = bytes.get(s + 1).copied();
                // `=>` arrow, `==`/`===` equality — not initializers.
                if next != Some(b'>') && next != Some(b'=') {
                    return None;
                }
                // Skip the second `=` so a later `=>` doesn't re-trigger.
                s += 1;
            }
            b';' | b'\n' if paren_depth == 0 => break,
            _ => {}
        }
        s += 1;
    }
    Some(name_end)
}

#[inline]
fn is_ascii_ws(b: u8) -> bool {
    matches!(b, b' ' | b'\t' | b'\n' | b'\r')
}

#[inline]
fn is_ident_byte(b: u8) -> bool {
    b.is_ascii_alphanumeric() || b == b'_' || b == b'$'
}

#[inline]
fn utf8_char_len(b: u8) -> usize {
    if b < 0xC0 {
        1
    } else if b < 0xE0 {
        2
    } else if b < 0xF0 {
        3
    } else {
        4
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use std::path::PathBuf;
    use svn_analyze::walk_template;
    use svn_parser::{parse_all_template_runs, parse_sections};

    fn emit_str(src: &str) -> String {
        emit_str_with_path(src, "/test/Anonymous.svelte")
    }

    fn emit_str_with_path(src: &str, path: &str) -> String {
        let (doc, errors) = parse_sections(src);
        assert!(errors.is_empty(), "parse errors: {errors:?}");
        let (fragment, errors) = parse_all_template_runs(src, &doc.template.text_runs);
        assert!(errors.is_empty(), "template parse errors: {errors:?}");
        let summary = walk_template(&fragment, src);
        emit_document(&doc, &fragment, &summary, &PathBuf::from(path)).typescript
    }

    #[test]
    fn empty_source_still_emits_scaffold() {
        let out = emit_str("");
        assert!(out.contains("function $$render_"));
        assert!(out.contains("__svn_tpl_check"));
        assert!(
            out.contains("void __svn_tpl_check;"),
            "expected per-statement void of __svn_tpl_check:\n{out}"
        );
    }

    #[test]
    fn render_name_includes_hash_suffix() {
        let out = emit_str("");
        // Scan for the function name and verify it has 8 hex chars after
        // the `$$render_` prefix.
        let idx = out.find("function $$render_").unwrap();
        let tail = &out[idx + "function $$render_".len()..];
        let suffix: String = tail.chars().take(8).collect();
        assert_eq!(suffix.len(), 8, "8-char suffix expected, got {suffix:?}");
        assert!(
            suffix.chars().all(|c| c.is_ascii_hexdigit()),
            "suffix should be hex, got {suffix:?}"
        );
    }

    #[test]
    fn different_paths_produce_different_render_names() {
        let a = emit_str_with_path("<p>hi</p>", "/test/A.svelte");
        let b = emit_str_with_path("<p>hi</p>", "/test/B.svelte");
        // Same content, different paths → different render names. This is
        // what stops the TS2393 cascade across multiple components in one
        // overlay project.
        let a_name = extract_render_name(&a);
        let b_name = extract_render_name(&b);
        assert_ne!(
            a_name, b_name,
            "different paths must hash to different render names"
        );
    }

    #[test]
    fn same_path_produces_stable_render_name() {
        let a1 = emit_str_with_path("<p>hi</p>", "/test/Foo.svelte");
        let a2 = emit_str_with_path("<p>hi</p>", "/test/Foo.svelte");
        assert_eq!(extract_render_name(&a1), extract_render_name(&a2));
    }

    fn extract_render_name(out: &str) -> String {
        let idx = out.find("function $$render_").unwrap();
        let tail = &out[idx + "function ".len()..];
        tail.chars()
            .take_while(|c| *c != '(' && *c != '<')
            .collect()
    }

    #[test]
    fn does_not_emit_svelte_reference_directive() {
        // /// <reference types="svelte" /> would trigger TS2688 in fixtures
        // that don't have the svelte package installed. We rely on the
        // user's environment to have svelte (or our future shim file)
        // rather than asserting it here.
        let out = emit_str("");
        assert!(!out.contains("<reference types=\"svelte\""));
    }

    #[test]
    fn imports_hoisted_above_render_function() {
        let src = "<script lang=\"ts\">\
                   import { writable } from 'svelte/store';\
                   const x = writable(0);\
                   </script>";
        let out = emit_str(src);
        let import_pos = out.find("import { writable }").expect("import present");
        let render_pos = out.find("function $$render_").expect("render present");
        assert!(
            import_pos < render_pos,
            "imports must be hoisted above the render function (found imports at {import_pos}, render at {render_pos})"
        );
    }

    #[test]
    fn imports_only_appear_once() {
        // Hoisted to module top-level — must NOT also appear inside
        // $$render. The body should have whitespace where the import was.
        let src = "<script lang=\"ts\">\
                   import { writable } from 'svelte/store';\
                   const x = writable(0);\
                   </script>";
        let out = emit_str(src);
        let count = out.matches("import { writable }").count();
        assert_eq!(count, 1);
    }

    #[test]
    fn passes_module_script_verbatim() {
        let out = emit_str("<script context=\"module\">export const A = 1;</script>");
        assert!(out.contains("export const A = 1;"));
    }

    #[test]
    fn template_check_wrapper_in_void_block() {
        let out = emit_str("<p>hi</p>");
        assert!(out.contains("void __svn_tpl_check;"));
    }

    #[test]
    fn use_directive_emits_action_attrs() {
        let out = emit_str("<div use:tooltip>x</div>");
        assert!(out.contains("__svn_action_attrs_0"));
        assert!(out.contains("let __svn_action_attrs_0"));
    }

    #[test]
    fn bind_pair_emits_bind_pair_declaration() {
        let out = emit_str("<input bind:value={() => g(), (v) => s(v)} />");
        assert!(out.contains("__svn_bind_pair_0"));
        assert!(out.contains("let __svn_bind_pair_0"));
    }

    #[test]
    fn render_function_is_referenced() {
        let out = emit_str("<p>hi</p>");
        // Self-reference is `<render_name>;` on its own line.
        assert!(out.contains("$$render_"));
        let render_name = extract_render_name(&out);
        assert!(out.contains(&format!("{render_name};")));
    }

    #[test]
    fn void_block_uses_per_statement_form() {
        // Switched from `void (a, b, c);` to `void X; void Y; void Z;`
        // — the consolidated form triggers TS2695 ("Left side of comma
        // operator is unused"). Each synthesized name gets its own
        // `void X;` line, and we should never emit the parenthesized
        // multi-name form.
        let out = emit_str("<div use:a use:b>x</div>");
        assert!(
            !out.contains("    void ("),
            "no parenthesized void(...) form expected:\n{out}"
        );
        assert!(out.contains("void __svn_action_attrs_0;"));
        assert!(out.contains("void __svn_action_attrs_1;"));
    }

    #[test]
    fn each_block_without_as_clause_uses_placeholder_binding() {
        let out = emit_str("{#each items}<span>x</span>{/each}");
        assert!(out.contains("for (const"), "missing for-of loop:\n{out}");
        assert!(
            !out.contains("for (const  of"),
            "empty binding produced double-space-before-`of`:\n{out}"
        );
    }

    #[test]
    fn each_block_with_binding_uses_user_name() {
        let out = emit_str("{#each items as item}<span>{item}</span>{/each}");
        assert!(out.contains("for (const item of"));
    }

    #[test]
    fn each_with_destructured_pattern() {
        let out = emit_str("{#each pairs as { a, b }}<x />{/each}");
        assert!(out.contains("for (const"));
        assert!(!out.contains("for (const  of"));
    }

    #[test]
    fn bind_this_target_gets_definite_assignment() {
        let src = "<script lang=\"ts\">let inputEl: HTMLDivElement;</script>\
                   <div bind:this={inputEl}></div>";
        let out = emit_str(src);
        assert!(
            out.contains("let inputEl!:"),
            "missing definite-assignment rewrite:\n{out}"
        );
        assert!(
            !out.contains("let inputEl: "),
            "still has un-rewritten declaration:\n{out}"
        );
    }

    #[test]
    fn non_bind_target_let_unchanged() {
        let src = "<script lang=\"ts\">let other: number = 1;</script>";
        let out = emit_str(src);
        assert!(
            out.contains("let other: number"),
            "non-bind-target should not be rewritten:\n{out}"
        );
        assert!(!out.contains("let other!"));
    }

    #[test]
    fn bind_target_with_initializer_unchanged() {
        let src = "<script lang=\"ts\">let inputEl = null as any as HTMLDivElement;</script>\
                   <div bind:this={inputEl}></div>";
        let out = emit_str(src);
        assert!(
            !out.contains("let inputEl!"),
            "shouldn't add `!` to declarations with initializers:\n{out}"
        );
    }

    #[test]
    fn no_generics_attribute_emits_plain_function() {
        let out = emit_str("<script lang=\"ts\">let x = 1;</script>");
        let render = extract_render_name(&out);
        assert!(out.contains(&format!("{render}() {{")));
        assert!(!out.contains(&format!("{render}<")));
    }

    #[test]
    fn simple_generics_attribute_threaded_into_function_signature() {
        // `<script generics="T">` puts T in scope inside the body.
        let src = "<script lang=\"ts\" generics=\"T\">let x: T;</script>";
        let out = emit_str(src);
        let render = extract_render_name(&out);
        assert!(
            out.contains(&format!("{render}<T>() {{")),
            "generic T should appear in function signature:\n{out}"
        );
    }

    #[test]
    fn generics_with_constraint_threaded_verbatim() {
        let src = "<script lang=\"ts\" generics=\"T extends Record<string, unknown>\">\
                   let x: T;</script>";
        let out = emit_str(src);
        assert!(
            out.contains("<T extends Record<string, unknown>>"),
            "constrained generic should be spliced verbatim:\n{out}"
        );
    }

    #[test]
    fn multiple_generics_threaded() {
        let src = "<script lang=\"ts\" generics=\"T, K extends keyof T\">\
                   let x: T;</script>";
        let out = emit_str(src);
        assert!(
            out.contains("<T, K extends keyof T>"),
            "multi-param generics should be spliced verbatim:\n{out}"
        );
    }

    #[test]
    fn empty_generics_attribute_treated_as_absent() {
        let src = "<script lang=\"ts\" generics=\"\">let x = 1;</script>";
        let out = emit_str(src);
        let render = extract_render_name(&out);
        assert!(out.contains(&format!("{render}() {{")));
        assert!(!out.contains(&format!("{render}<")));
    }
}
